INSERT INTO notices (title, category, author, department, publish_date, summary, content, is_top, created_at) VALUES
-- 党委通知 - 置顶
('关于深入学习贯彻党的二十大精神的实施方案', '党委通知', '中共计算机学院委员会', '计算机学院党委办公室', '2025-12-05 09:00:00', '为深入学习贯彻党的二十大精神，制定本实施方案', '<p>各党支部、全体党员：</p><p>为深入学习贯彻党的二十大精神，切实把全院党员干部和师生员工的思想统一到党的二十大精神上来，把力量凝聚到党的二十大确定的各项任务上来，根据上级党委部署要求，结合学院实际，制定本实施方案。</p><h3>一、总体要求</h3><p>坚持以习近平新时代中国特色社会主义思想为指导，全面贯彻落实党的二十大精神，深刻领悟"两个确立"的决定性意义，增强"四个意识"、坚定"四个自信"、做到"两个维护"。</p><h3>二、学习内容</h3><p>1. 党的二十大报告全文</p><p>2. 《中国共产党章程（修正案）》</p><p>3. 习近平总书记在党的二十大开幕会上的重要讲话</p><p>4. 习近平总书记在二十届一中全会上的重要讲话</p><h3>三、学习安排</h3><p><strong>第一阶段：集中学习（2025年12月-2026年1月）</strong></p><p>1. 党委理论学习中心组学习：每周一次，共6次</p><p>2. 党支部学习：每周一次，共8次</p><p>3. 全体党员集中学习：每月一次，共2次</p><p><strong>第二阶段：专题研讨（2026年2月-3月）</strong></p><p>围绕"党的二十大精神与学院高质量发展"等主题开展专题研讨</p><p><strong>第三阶段：实践应用（2026年4月-12月）</strong></p><p>将学习成果转化为推动学院各项工作的实际行动</p><h3>四、工作要求</h3><p>1. 加强组织领导，确保学习效果</p><p>2. 创新学习方式，增强学习吸引力</p><p>3. 注重学用结合，推动工作落实</p><p>4. 强化督促检查，确保学习任务完成</p><p>附件：1. 党的二十大报告全文</p><p>2. 《中国共产党章程（修正案）》</p><p>3. 学习计划表</p><p>中共计算机学院委员会</p><p>2025年12月5日</p>', 1, '2025-12-05 09:00:00'),

-- 学术通知
('关于举办2025年计算机科学前沿论坛的通知', '学术通知', '计算机学院学术委员会', '计算机学院科研办公室', '2025-12-06 14:30:00', '2025年计算机科学前沿论坛即将举行，邀请知名专家学者作报告', '<p>各位老师、同学：</p><p>为促进学术交流，把握计算机科学前沿动态，计算机学院将于近期举办2025年计算机科学前沿论坛。现将有关事项通知如下：</p><h3>一、论坛主题</h3><p>人工智能与计算机科学的融合发展</p><h3>二、时间地点</h3><p>时间：2025年12月20日（星期六）上午9:00-17:30</p><p>地点：学院学术报告厅（科技楼A座101）</p><h3>三、主讲嘉宾</h3><p>1. 张教授 - 清华大学计算机科学与技术系，人工智能领域专家</p><p>2. 李院士 - 中国科学院计算技术研究所，计算机体系结构专家</p><p>3. 王教授 - 北京大学信息科学技术学院，大数据分析专家</p><p>4. 赵教授 - 上海交通大学计算机科学与工程系，网络安全专家</p><h3>四、论坛议程</h3><p><strong>上午（9:00-12:00）</strong></p><p>9:00-9:15 开幕式 主持人：学院院长</p><p>9:15-10:15 张教授：《人工智能大模型的发展与挑战》</p><p>10:15-10:30 茶歇</p><p>10:30-11:30 李院士：《计算机体系结构的新趋势》</p><p>11:30-12:00 提问交流</p><p><strong>下午（14:00-17:30）</strong></p><p>14:00-15:00 王教授：《大数据分析在各领域的应用》</p><p>15:00-15:15 茶歇</p><p>15:15-16:15 赵教授：《网络安全的现状与未来》</p><p>16:15-17:00 圆桌论坛：《人工智能时代的计算机教育》</p><p>17:00-17:30 闭幕式 主持人：学院党委书记</p><h3>五、参会方式</h3><p>1. 现场参会：请于12月15日前在学院网站报名</p><p>2. 线上参会：通过腾讯会议直播，会议号将在报名后发送</p><h3>六、联系方式</h3><p>联系人：刘老师</p><p>联系电话：8888-8890</p><p>邮箱：conference@computer.edu.cn</p><p>计算机学院学术委员会</p><p>2025年12月6日</p>', 0, '2025-12-06 14:30:00'),

-- 学生通知
('关于2025年国家奖学金评审工作的通知', '学生通知', '计算机学院学生工作办公室', '计算机学院学生工作办公室', '2025-12-02 10:00:00', '2025年国家奖学金评审工作开始，符合条件的学生可申请', '<p>各位同学：</p><p>根据《普通本科高校、高等职业学校国家奖学金管理暂行办法》和学校有关规定，现将2025年国家奖学金评审工作有关事项通知如下：</p><h3>一、评选对象</h3><p>我院全日制本科二年级及以上学生</p><h3>二、评选条件</h3><p>1. 热爱社会主义祖国，拥护中国共产党的领导</p><p>2. 遵守宪法和法律，遵守学校规章制度</p><p>3. 诚实守信，道德品质优良</p><p>4. 在校期间学习成绩优异，上一学年平均成绩在85分以上，综合素质排名在本专业前10%</p><p>5. 社会实践、创新能力、综合素质等方面特别突出</p><h3>三、奖励标准</h3><p>国家奖学金每人每年8000元</p><h3>四、申请材料</h3><p>1. 《普通本科高校国家奖学金申请表》</p><p>2. 成绩单（加盖教务处公章）</p><p>3. 综合素质证明材料（获奖证书、科研成果等）</p><p>4. 个人事迹材料（1500字左右）</p><h3>五、评审程序</h3><p>1. 学生申请：12月5日前提交申请材料</p><p>2. 班级评审：12月6日-12月8日</p><p>3. 学院评审：12月9日-12月12日</p><p>4. 公示：12月13日-12月19日</p><p>5. 学校评审：12月20日-12月31日</p><h3>六、联系方式</h3><p>联系人：陈老师</p><p>联系电话：8888-8891</p><p>办公地点：学生工作办公室（行政楼302）</p><p>计算机学院学生工作办公室</p><p>2025年12月2日</p>', 0, '2025-12-02 10:00:00'),

-- 教学通知
('关于2025-2026学年第一学期期末考试安排的通知', '教学通知', '计算机学院教学办公室', '计算机学院教学办公室', '2025-12-03 11:00:00', '2025-2026学年第一学期期末考试安排已发布', '<p>各位老师、同学：</p><p>现将2025-2026学年第一学期期末考试安排通知如下：</p><h3>一、考试时间</h3><p>2026年1月10日（星期五）至1月20日（星期一）</p><h3>二、考试科目</h3><p><strong>本科一年级：</strong></p><p>高等数学、大学物理、程序设计基础、英语等</p><p><strong>本科二年级：</strong></p><p>数据结构、操作系统、计算机组成原理、离散数学等</p><p><strong>本科三年级：</strong></p><p>人工智能、机器学习、计算机网络、数据库系统等</p><p><strong>本科四年级：</strong></p><p>专业选修课程、毕业设计（论文）中期检查等</p><h3>三、考试要求</h3><p>1. 学生必须携带学生证和身份证参加考试</p><p>2. 严格遵守考试纪律，严禁作弊</p><p>3. 提前15分钟进入考场，迟到30分钟不得进入考场</p><p>4. 手机等通讯工具必须关机并放在指定位置</p><h3>四、成绩查询</h3><p>考试成绩将于2026年2月10日通过学院网站公布</p><h3>五、联系方式</h3><p>联系人：王老师</p><p>联系电话：8888-8892</p><p>邮箱：teaching@computer.edu.cn</p><p>附件：2025-2026学年第一学期期末考试安排表</p><p>计算机学院教学办公室</p><p>2025年12月3日</p>', 0, '2025-12-03 11:00:00'),

-- 科研通知
('关于申报2026年度国家自然科学基金项目的通知', '科研通知', '计算机学院科研办公室', '计算机学院科研办公室', '2025-12-01 16:00:00', '2026年度国家自然科学基金项目申报工作开始', '<p>各位老师：</p><p>现将2026年度国家自然科学基金项目申报工作有关事项通知如下：</p><h3>一、申报类型</h3><p>1. 面上项目</p><p>2. 青年科学基金项目</p><p>3. 地区科学基金项目</p><p>4. 重点项目</p><p>5. 重大项目</p><p>6. 国际（地区）合作与交流项目</p><h3>二、申报条件</h3><p>详见《国家自然科学基金项目管理办法》和《2026年度国家自然科学基金项目指南》</p><h3>三、申报时间</h3><p>1. 学院内部截止时间：2026年1月15日</p><p>2. 学校截止时间：2026年1月20日</p><p>3. 国家自然科学基金委员会截止时间：2026年3月1日</p><h3>四、申报要求</h3><p>1. 认真阅读《2026年度国家自然科学基金项目指南》</p><p>2. 严格按照要求填写申请书</p><p>3. 确保申请书内容真实、准确、完整</p><p>4. 提交纸质申请书一式三份，电子版一份</p><h3>五、联系方式</h3><p>联系人：黄老师</p><p>联系电话：8888-8893</p><p>邮箱：research@computer.edu.cn</p><p>附件：1. 《2026年度国家自然科学基金项目指南》</p><p>2. 《国家自然科学基金项目管理办法》</p><p>3. 申请书模板</p><p>计算机学院科研办公室</p><p>2025年12月1日</p>', 0, '2025-12-01 16:00:00'),

-- 安全通知
('关于加强冬季校园安全工作的通知', '安全通知', '计算机学院保卫处', '计算机学院保卫处', '2025-12-04 09:30:00', '冬季来临，为加强校园安全工作，保障师生生命财产安全', '<p>各部门、各位师生：</p><p>冬季来临，天干物燥，是火灾、盗窃等安全事故的高发期。为加强校园安全工作，保障师生生命财产安全，现将有关事项通知如下：</p><h3>一、消防安全</h3><p>1. 严禁在宿舍、办公室内使用大功率电器（如电暖器、电磁炉等）</p><p>2. 严禁在校园内吸烟，特别是在教学楼、实验室等场所</p><p>3. 定期检查消防设施设备，确保完好有效</p><p>4. 掌握基本的消防知识和灭火技能</p><h3>二、用电安全</h3><p>1. 离开办公室、宿舍时，关闭所有电器设备电源</p><p>2. 严禁私拉乱接电线</p><p>3. 定期检查电器设备，发现问题及时维修</p><h3>三、防盗安全</h3><p>1. 离开办公室、宿舍时，关好门窗</p><p>2. 贵重物品要妥善保管，不要随意放置</p><p>3. 校园内发现可疑人员，及时向保卫处报告</p><h3>四、交通安全</h3><p>1. 遵守交通规则，过马路走人行横道</p><p>2. 骑自行车、电动车时要佩戴头盔</p><p>3. 冬季路面湿滑，注意行车安全</p><h3>五、应急处置</h3><p>1. 熟悉校园内的安全出口和疏散通道</p><p>2. 发生安全事故时，要保持冷静，及时报警并采取相应的应急措施</p><h3>六、联系方式</h3><p>保卫处24小时值班电话：8888-8899</p><p>计算机学院保卫处</p><p>2025年12月4日</p>', 0, '2025-12-04 09:30:00');

